cy.request('GET', '/patients').then(response => {
  expect(response.status).to.equal(200);
  expect(response.body).to.be.an('array');
  expect(response.body.some(p => p.id === patientId)).to.equal(true);
});

cy.request({
  method: 'POST',
  url: '/patients',
  failOnStatusCode: false,
  body: {
    phone: '(85) 90000-0000'
  }
}).then(response => {
  expect(response.status).to.equal(400);
  expect(response.body.message).to.equal('Nome do paciente e obrigatorio');
});

cy.request({
  method: 'POST',
  url: '/patients',
  failOnStatusCode: false,
  body: {
    name: '1',
    phone: '(85) 99999-0000',
    diagnosis: 'Teste'
  }
}).then(response => {
  expect(response.status).to.equal(400);
  expect(response.body.message).to.equal('Nome do paciente invalido');
});

cy.request({
  method: 'POST',
